/**
 * Get the best default image for an ad based on category/subcategory.
 * Priority: real uploaded image → subcategory image → category image → global fallback
 */
export function getAdDefaultImage(ad) {
  if (ad?.images?.length > 0) {
    const img = ad.images[0];
    if (img && !img.includes('placeholder') && img.trim() !== '') {
      if (img.startsWith('http')) return img;
      if (img.startsWith('/category-images')) return img;
      return `https://res.cloudinary.com/dni9wcvx3/image/upload/f_auto,q_auto,w_400,c_limit/${img}`;
    }
  }
  // Try subcategory first, then category
  const sub = ad?.subcategory;
  const cat = ad?.category;
  if (sub && CATEGORY_IMAGES[sub]) return CATEGORY_IMAGES[sub];
  if (cat && CATEGORY_IMAGES[cat]) return CATEGORY_IMAGES[cat];
  return `${BASE}/other.jpg`;
}
